form:Form.form:Scripts:
		function SendToServer()
{       
	GetProxy().StoreService().SetUserStore("PER_IDsLegajosAcc", array2stringcustom(arrB, "ROWS", "ROW"));
	return true;
}

function Filtrar()
{
	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

 	if (Ctrl("list2").TotalRowsCount()>100)
 	{             
 		alert("Hay demasiados registros seleccionados, afine la búsqueda.");
 		return false;
 	}
	SendToServer();
	Ctrl("main").DoEvent("FILTER");
}

function enable_custom_buttons()
{
	if (Ctrl("list2"))
		CtrlEnabled("btnFILTER", Ctrl("list2").TotalRowsCount()?true:false);
}
